import{_ as d,o as a,c as r,a4 as e}from"./chunks/framework.ChErgFjV.js";const q=JSON.parse('{"title":"第一章 教育基础知识和基本原理","description":"","frontmatter":{"title":"第一章 教育基础知识和基本原理","date":"2026-07-08T00:00:00.000Z","tags":["教师资格考试","教育知识与能力"]},"headers":[],"relativePath":"study/teacher-cert/education-knowledge/chapter1.md","filePath":"study/teacher-cert/education-knowledge/chapter1.md","lastUpdated":1783652711000}'),l={name:"study/teacher-cert/education-knowledge/chapter1.md"};function o(h,t,i,n,b,s){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第一章-教育基础知识和基本原理" tabindex="-1">第一章 教育基础知识和基本原理 <a class="header-anchor" href="#第一章-教育基础知识和基本原理" aria-label="Permalink to &quot;第一章 教育基础知识和基本原理&quot;">​</a></h1><blockquote><p>本章考情：全题型覆盖，约 20-25 分 重点：教育起源、教育与社会发展、教育与人的发展、教育目的</p></blockquote><hr><h2 id="_1-1-教育的概念-🔴🔴" tabindex="-1">1.1 教育的概念 🔴🔴 <a class="header-anchor" href="#_1-1-教育的概念-🔴🔴" aria-label="Permalink to &quot;1.1 教育的概念 🔴🔴&quot;">​</a></h2><h3 id="教育的定义" tabindex="-1">教育的定义 <a class="header-anchor" href="#教育的定义" aria-label="Permalink to &quot;教育的定义&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>定义</th><th>要点</th></tr></thead><tbody><tr><td>广义教育</td><td>一切增进人的知识和技能、发展人的智力和体力、影响人的思想品德的活动</td><td>范围最广，含家庭教育、社会教育、学校教育</td></tr><tr><td>狭义教育</td><td>学校教育，教育者按一定社会要求，有目的、有计划、有组织地对受教育者施加影响</td><td>三有：有目的、有计划、有组织</td></tr><tr><td>更狭义教育</td><td>思想品德教育（德育）</td><td>特指德育</td></tr></tbody></table><h3 id="教育的基本要素-🔴" tabindex="-1">教育的基本要素 🔴 <a class="header-anchor" href="#教育的基本要素-🔴" aria-label="Permalink to &quot;教育的基本要素 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>要素</th><th>含义</th><th>地位</th></tr></thead><tbody><tr><td>教育者</td><td>对受教育者在知识、技能、思想品德等方面施加影响的人</td><td>主导者</td></tr><tr><td>受教育者</td><td>接受教育的人</td><td>主体</td></tr><tr><td>教育影响</td><td>教育内容+教育手段（方法、组织形式等）</td><td>中介/纽带</td></tr></tbody></table><p><strong>三者关系</strong>：教育者→教育影响→受教育者，受教育者的反馈→教育者</p><h3 id="教育属性-🔴🔴" tabindex="-1">教育属性 🔴🔴 <a class="header-anchor" href="#教育属性-🔴🔴" aria-label="Permalink to &quot;教育属性 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性类型</th><th>内容</th><th>判断关键词</th></tr></thead><tbody><tr><td>本质属性</td><td>教育是有目的地培养人的社会活动 🔴🔴</td><td>目的性、培养人、社会性</td></tr><tr><td>社会属性</td><td>永恒性（与人类共始终）、历史性（随社会变化）、相对独立性</td><td>永恒、历史变化、独立性</td></tr></tbody></table><p><strong>易错辨析</strong>：</p><ul><li>❌ &quot;教育永远存在&quot; → ✅ 永恒性（人类社会存在就有教育）</li><li>❌ &quot;古今教育相同&quot; → ✅ 历史性（不同历史时期教育不同）</li><li>❌ &quot;教育完全由社会决定&quot; → ✅ 相对独立性（有自身规律，受制约但不完全被动）</li></ul><hr><h2 id="_1-2-教育的起源-🔴🔴🔴" tabindex="-1">1.2 教育的起源 🔴🔴🔴 <a class="header-anchor" href="#_1-2-教育的起源-🔴🔴🔴" aria-label="Permalink to &quot;1.2 教育的起源 🔴🔴🔴&quot;">​</a></h2><h3 id="三种起源学说" tabindex="-1">三种起源学说 <a class="header-anchor" href="#三种起源学说" aria-label="Permalink to &quot;三种起源学说&quot;">​</a></h3><table tabindex="0"><thead><tr><th>学说</th><th>代表人物</th><th>核心观点</th><th>评价</th><th>判断关键词</th></tr></thead><tbody><tr><td>生物起源说</td><td>利托尔诺、沛西·能</td><td>教育是动物的本能活动</td><td>❌ 否认了教育的社会性和目的性</td><td>动物本能、天生</td></tr><tr><td>心理起源说</td><td>孟禄</td><td>教育是儿童对成人无意识模仿</td><td>❌ 否认了教育的意识性（目的性）</td><td>无意识模仿</td></tr><tr><td>劳动起源说</td><td>米丁斯基</td><td>教育起源于劳动过程中社会生产需要和人的发展需要的统一</td><td>✅ 马克思主义观点</td><td>劳动、社会需要</td></tr></tbody></table><p><strong>辨析题高频</strong> 🔴🔴：</p><ul><li>&quot;教育是人与动物共有的&quot; → ❌ 错误。教育是人类特有的社会活动，动物本能不是教育</li><li>&quot;教育起源于儿童对成人的无意识模仿&quot; → ❌ 错误。这是心理起源说，否认了教育的目的性和意识性</li></ul><hr><h2 id="_1-3-教育发展历程-🔴" tabindex="-1">1.3 教育发展历程 🔴 <a class="header-anchor" href="#_1-3-教育发展历程-🔴" aria-label="Permalink to &quot;1.3 教育发展历程 🔴&quot;">​</a></h2><h3 id="古代教育" tabindex="-1">古代教育 <a class="header-anchor" href="#古代教育" aria-label="Permalink to &quot;古代教育&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时期</th><th>特征</th><th>代表</th></tr></thead><tbody><tr><td>中国夏商</td><td>&quot;庠&quot;&quot;序&quot; — 最早的学校</td><td>学校萌芽</td></tr><tr><td>中国西周</td><td>学在官府、政教合一 🔴</td><td>官学垄断</td></tr><tr><td>中国春秋战国</td><td>私学兴起 🔴</td><td>孔子办私学、稷下学宫</td></tr><tr><td>中国汉代</td><td>独尊儒术、太学</td><td>察举制</td></tr><tr><td>中国隋唐</td><td>科举制 🔴</td><td>分科考试取士</td></tr><tr><td>中国宋代</td><td>书院兴盛</td><td>白鹿洞书院</td></tr><tr><td>古埃及</td><td>以僧为师、以吏为师</td><td>文士学校</td></tr><tr><td>古希腊斯巴达</td><td>军事体育训练</td><td>尚武</td></tr><tr><td>古希腊雅典 🔴</td><td>身心和谐发展</td><td>文武兼备</td></tr><tr><td>中世纪欧洲</td><td>教会教育+骑士教育</td><td>七艺（三科四学）</td></tr></tbody></table><p><strong>古代教育共同特征</strong>：</p><ol><li>产生了学校，教育成为专门的社会职能</li><li>具有阶级性和等级性 🔴</li><li>与生产劳动相脱离 🔴</li><li>道统性、专制性、刻板性</li></ol><hr><h2 id="_1-4-教育与社会发展-🔴🔴🔴" tabindex="-1">1.4 教育与社会发展 🔴🔴🔴 <a class="header-anchor" href="#_1-4-教育与社会发展-🔴🔴🔴" aria-label="Permalink to &quot;1.4 教育与社会发展 🔴🔴🔴&quot;">​</a></h2><h3 id="教育与生产力-🔴🔴" tabindex="-1">教育与生产力 🔴🔴 <a class="header-anchor" href="#教育与生产力-🔴🔴" aria-label="Permalink to &quot;教育与生产力 🔴🔴&quot;">​</a></h3><p><strong>生产力对教育的制约</strong>（口诀：龟速够防守）：</p><table tabindex="0"><thead><tr><th>制约方面</th><th>具体表现</th></tr></thead><tbody><tr><td>制约教育规模和速度</td><td>生产力水平高→教育规模大、速度快</td></tr><tr><td>制约人才培养的规格</td><td>不同生产力水平需要不同类型人才</td></tr><tr><td>制约教育结构</td><td>产业结构变化→教育结构调整</td></tr><tr><td>制约教育内容和方法</td><td>现代科技→教学内容更新、方法现代化</td></tr></tbody></table><p><strong>教育对生产力的促进作用</strong>（经济功能，口诀：两再一新）：</p><ol><li>劳动力再生产 — 教育把可能的劳动力变为现实的劳动力</li><li>科学知识再生产 — 教育传播科学知识</li><li>技术创新 — 高等教育推动科技创新</li></ol><h3 id="教育与政治经济制度-🔴🔴" tabindex="-1">教育与政治经济制度 🔴🔴 <a class="header-anchor" href="#教育与政治经济制度-🔴🔴" aria-label="Permalink to &quot;教育与政治经济制度 🔴🔴&quot;">​</a></h3><p><strong>政治经济制度对教育的制约</strong>（口诀：体内性质权）：</p><ol><li>决定教育的领导权</li><li>决定受教育的权利和程度</li><li>决定教育目的的性质和思想品德教育内容</li></ol><p><strong>教育对政治经济制度的促进作用</strong>（政治功能）：</p><ol><li>培养合格公民和政治人才</li><li>传播政治思想，形成舆论</li><li>促进政治民主化</li></ol><h3 id="教育与文化-🔴" tabindex="-1">教育与文化 🔴 <a class="header-anchor" href="#教育与文化-🔴" aria-label="Permalink to &quot;教育与文化 🔴&quot;">​</a></h3><p><strong>文化对教育的制约</strong>：内容、环境、模式</p><p><strong>教育的文化功能</strong>（口诀：传选创融）：</p><ol><li>传承文化 — 最基本的功能</li><li>筛选、整理文化</li><li>交流、融合文化</li><li>更新、创造文化</li></ol><hr><h2 id="_1-5-教育与人的发展-🔴🔴🔴" tabindex="-1">1.5 教育与人的发展 🔴🔴🔴 <a class="header-anchor" href="#_1-5-教育与人的发展-🔴🔴🔴" aria-label="Permalink to &quot;1.5 教育与人的发展 🔴🔴🔴&quot;">​</a></h2><blockquote><p>高频大题区域</p></blockquote><h3 id="人身心发展的规律-🔴🔴🔴" tabindex="-1">人身心发展的规律 🔴🔴🔴 <a class="header-anchor" href="#人身心发展的规律-🔴🔴🔴" aria-label="Permalink to &quot;人身心发展的规律 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>规律</th><th>含义</th><th>教育启示</th><th>口诀</th></tr></thead><tbody><tr><td>顺序性</td><td>由低到高、由简到繁、由量变到质变</td><td>循序渐进，不可拔苗助长 🔴</td><td>顺</td></tr><tr><td>阶段性</td><td>不同年龄阶段有不同特征</td><td>分阶段教育，不能一刀切 🔴</td><td>阶</td></tr><tr><td>不平衡性</td><td>同一方面不同速、不同方面不同步</td><td>抓关键期 🔴🔴</td><td>不</td></tr><tr><td>互补性</td><td>机能之间可以互补</td><td>扬长避短，长善救失</td><td>补</td></tr><tr><td>个别差异性</td><td>人与人之间有差异</td><td>因材施教 🔴</td><td>差</td></tr></tbody></table><p><strong>口诀</strong>：顺阶不补差</p><p><strong>辨析题高频</strong> 🔴🔴：</p><ul><li>&quot;教育要循序渐进，不能拔苗助长&quot; → ✅ 体现了顺序性</li><li>&quot;人的发展有关键期，错过就补不回来&quot; → ✅ 体现了不平衡性</li><li>&quot;因材施教体现了个别差异性&quot; → ✅ 正确</li></ul><h3 id="影响人身心发展的因素-🔴🔴🔴" tabindex="-1">影响人身心发展的因素 🔴🔴🔴 <a class="header-anchor" href="#影响人身心发展的因素-🔴🔴🔴" aria-label="Permalink to &quot;影响人身心发展的因素 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>因素</th><th>作用</th><th>地位</th><th>判断关键词</th></tr></thead><tbody><tr><td>遗传</td><td>提供物质前提和可能性</td><td>物质前提/可能性</td><td>天生、先天、生理基础</td></tr><tr><td>环境</td><td>提供发展的现实条件</td><td>现实基础/外部条件</td><td>后天、周围、外部</td></tr><tr><td>学校教育 🔴🔴</td><td>主导作用</td><td>主导</td><td>有目的有计划、系统、教师指导</td></tr><tr><td>个体主观能动性 🔴</td><td>决定作用</td><td>决定因素</td><td>主动、努力、内因</td></tr></tbody></table><p><strong>学校教育起主导作用的条件</strong> 🔴🔴：</p><ol><li>学校教育是有目的、有计划、有组织的</li><li>有专门的教育者（教师）</li><li>能有效控制和协调影响学生发展的各种因素</li><li>给学生的影响较系统、较全面</li></ol><p><strong>辨析题</strong> 🔴🔴：</p><ul><li>&quot;遗传决定人的发展&quot; → ❌ 错误。遗传仅提供物质前提，不起决定作用</li><li>&quot;环境决定人的发展&quot; → ❌ 错误。环境影响但不起决定作用</li><li>&quot;学校教育对人的发展起决定作用&quot; → ❌ 错误。学校教育起主导作用，非决定作用</li><li>&quot;人的主观能动性是发展的决定因素&quot; → ✅ 正确</li></ul><hr><h2 id="_1-6-教育目的-🔴🔴" tabindex="-1">1.6 教育目的 🔴🔴 <a class="header-anchor" href="#_1-6-教育目的-🔴🔴" aria-label="Permalink to &quot;1.6 教育目的 🔴🔴&quot;">​</a></h2><h3 id="教育目的理论-🔴🔴" tabindex="-1">教育目的理论 🔴🔴 <a class="header-anchor" href="#教育目的理论-🔴🔴" aria-label="Permalink to &quot;教育目的理论 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>理论</th><th>代表人物</th><th>核心观点</th><th>评价</th></tr></thead><tbody><tr><td>社会本位论</td><td>涂尔干、孔德、赫尔巴特</td><td>教育目的是培养合格公民和社会劳动者</td><td>忽视个人发展</td></tr><tr><td>个人本位论</td><td>卢梭、裴斯泰洛齐、马斯洛</td><td>教育目的是发展人的本性、增进个人价值</td><td>忽视社会需要</td></tr><tr><td>生活本位论</td><td>斯宾塞</td><td>教育是为完满生活做准备</td><td>实用主义</td></tr><tr><td>文化本位论</td><td>斯普朗格</td><td>教育是文化的过程</td><td>—</td></tr></tbody></table><p><strong>辨析题</strong> 🔴：</p><ul><li>&quot;教育目的是为社会培养人才，不需要考虑个人发展&quot; → ❌ 这是社会本位论，忽视了个人发展</li></ul><h3 id="我国教育目的-🔴🔴" tabindex="-1">我国教育目的 🔴🔴 <a class="header-anchor" href="#我国教育目的-🔴🔴" aria-label="Permalink to &quot;我国教育目的 🔴🔴&quot;">​</a></h3><p><strong>基本特征</strong>：</p><ol><li>要求培养德智体美劳全面发展的社会主义建设者和接班人</li><li>要求坚持脑力劳动与体力劳动相结合</li><li>要求坚持政治思想道德素质与科学文化知识能力的统一</li></ol><p><strong>确立依据</strong>：</p><ol><li>社会生产力和科学技术发展水平</li><li>社会制度和政治经济状况</li><li>青少年身心发展规律</li><li>人的发展需要</li></ol><hr><h2 id="_1-7-教育制度-🔴" tabindex="-1">1.7 教育制度 🔴 <a class="header-anchor" href="#_1-7-教育制度-🔴" aria-label="Permalink to &quot;1.7 教育制度 🔴&quot;">​</a></h2><h3 id="学制类型" tabindex="-1">学制类型 <a class="header-anchor" href="#学制类型" aria-label="Permalink to &quot;学制类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>特点</th><th>代表国家</th></tr></thead><tbody><tr><td>双轨制</td><td>学术教育与职业教育并行，互不相通</td><td>英国 🔴</td></tr><tr><td>单轨制</td><td>统一学制，自下而上</td><td>美国 🔴</td></tr><tr><td>分支型学制</td><td>基础阶段统一，之后分轨</td><td>中国/苏联 🔴</td></tr></tbody></table><h3 id="我国现行学制" tabindex="-1">我国现行学制 <a class="header-anchor" href="#我国现行学制" aria-label="Permalink to &quot;我国现行学制&quot;">​</a></h3><ul><li><strong>类型</strong>：分支型学制</li><li><strong>结构</strong>：学前教育→初等教育→中等教育→高等教育</li><li><strong>义务教育</strong>：九年（小学+初中）</li><li><strong>发展趋势</strong>：终身教育体系构建</li></ul><hr><h2 id="本章速记卡" tabindex="-1">本章速记卡 <a class="header-anchor" href="#本章速记卡" aria-label="Permalink to &quot;本章速记卡&quot;">​</a></h2><h3 id="口诀汇总" tabindex="-1">口诀汇总 <a class="header-anchor" href="#口诀汇总" aria-label="Permalink to &quot;口诀汇总&quot;">​</a></h3><table tabindex="0"><thead><tr><th>知识点</th><th>口诀</th></tr></thead><tbody><tr><td>教育起源</td><td>生物（动物本能）→心理（无意识模仿）→劳动（正确）</td></tr><tr><td>生产力制约教育</td><td>龟速够防守（规速构方）</td></tr><tr><td>教育经济功能</td><td>两再一新</td></tr><tr><td>教育文化功能</td><td>传选创融</td></tr><tr><td>身心发展规律</td><td>顺阶不补差</td></tr><tr><td>影响发展因素</td><td>遗传（前提）→环境（基础）→学校教育（主导）→主观能动性（决定）</td></tr><tr><td>学制类型</td><td>英双美单中分支</td></tr></tbody></table><h3 id="辨析题必背判断" tabindex="-1">辨析题必背判断 <a class="header-anchor" href="#辨析题必背判断" aria-label="Permalink to &quot;辨析题必背判断&quot;">​</a></h3><table tabindex="0"><thead><tr><th>说法</th><th>判断</th></tr></thead><tbody><tr><td>教育是人与动物共有的</td><td>❌ 教育是人类特有的</td></tr><tr><td>教育起源于儿童无意识模仿</td><td>❌ 这是心理起源说</td></tr><tr><td>遗传决定人的发展</td><td>❌ 遗传只是物质前提</td></tr><tr><td>环境决定人的发展</td><td>❌ 环境不是决定因素</td></tr><tr><td>学校教育起决定作用</td><td>❌ 起主导作用，非决定</td></tr><tr><td>人的主观能动性决定发展</td><td>✅</td></tr></tbody></table>',78)])])}const c=d(l,[["render",o]]);export{q as __pageData,c as default};
